import React from 'react';
import { HashRouter as Router, Routes, Route, useLocation } from 'react-router-dom';
import Navbar from './components/Navbar';
import Footer from './components/Footer';
import BottomNav from './components/BottomNav';
import Home from './pages/Home';
import ProductView from './pages/ProductView';
import Profile from './pages/Profile';
import Admin from './pages/Admin';
import Auth from './pages/Auth';
import Cart from './pages/Cart';
import News from './pages/News';
import BlogView from './pages/BlogView'; 
import Rules from './pages/Rules'; 
import DynamicPage from './pages/DynamicPage'; 
import AllCategories from './pages/AllCategories'; 
import Balance from './pages/Balance';
import Contact from './pages/Contact'; 
import CategoryPage from './pages/CategoryPage';
import SearchPage from './pages/SearchPage';
import FloatingBalance from './components/FloatingBalance';
import { AppProvider } from './store';
import ChatWidget from './components/ChatWidget';
import CartWidget from './components/CartWidget';

const Layout = ({ children }: { children?: React.ReactNode }) => {
  const location = useLocation();
  const isAdminPage = location.pathname.startsWith('/admin');
  const isAuthPage = location.pathname === '/auth';

  // FIX: 
  // Desktop Header: pt-24 (Standard)
  // Mobile Header: pt-20 (Reduced from 110px to remove meaningless whitespace)

  return (
    <div className="flex flex-col min-h-screen">
      {!isAdminPage && !isAuthPage && <Navbar />}

      <main className={`flex-grow relative ${!isAdminPage && !isAuthPage ? 'pt-20 md:pt-24 pb-[90px] md:pb-0' : ''}`}>
        {children}
      </main>

      {!isAdminPage && !isAuthPage && <Footer />}
      {!isAdminPage && !isAuthPage && <BottomNav />}
      {!isAdminPage && !isAuthPage && <ChatWidget />}

      {/* CartWidget is always mounted to handle drawer state, handles its own visibility */}
      {!isAdminPage && !isAuthPage && <CartWidget />}
    </div>
  );
};

const App = () => {
  return (
    <AppProvider>
      <Router>
        <Layout>
          <Routes>
            <Route path="/" element={<Home />} />
            <Route path="/auth" element={<Auth />} />
            <Route path="/cart" element={<Cart />} />
            <Route path="/news" element={<News />} />
            <Route path="/news/:id" element={<BlogView />} />
            <Route path="/rules" element={<Rules />} />
            <Route path="/page/:slug" element={<DynamicPage />} /> {/* CMS Pages */}
            <Route path="/categories" element={<AllCategories />} /> {/* Grid Categories */}
            <Route path="/balance" element={<Balance />} />
            <Route path="/contact" element={<Contact />} />
            <Route path="/category/:id" element={<CategoryPage />} />
            <Route path="/search" element={<SearchPage />} />
            <Route path="/product/:id" element={<ProductView />} />
            <Route path="/profile" element={<Profile />} />
            <Route path="/admin" element={<Admin />} />
          </Routes>
        </Layout>
      </Router>
    </AppProvider>
  );
};

export default App;

import React, { useEffect, useState, useRef } from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { Bell, ChevronDown, User as UserIcon, Heart, Search, LogOut, Plus, Menu } from 'lucide-react';
import { useApp } from '../store';
import SideDrawer from './SideDrawer';

const Navbar = () => {
  const { user, isAuthenticated, notifications, markNotificationRead, clearNotifications, logout, openCart } = useApp();
  const [notifOpen, setNotifOpen] = useState(false);
  const [profileOpen, setProfileOpen] = useState(false);
  const [drawerOpen, setDrawerOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');

  const location = useLocation();
  const navigate = useNavigate();
  const notifRef = useRef<HTMLDivElement>(null);
  const profileRef = useRef<HTMLDivElement>(null);

  // Scroll & Header Logic
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
        setScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (notifRef.current && !notifRef.current.contains(event.target as Node)) setNotifOpen(false);
      if (profileRef.current && !profileRef.current.contains(event.target as Node)) setProfileOpen(false);
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  const handleSearch = (e: React.FormEvent) => {
      e.preventDefault();
      if(searchQuery.trim()) {
          navigate(`/search?q=${encodeURIComponent(searchQuery)}`);
      }
  };

  const myNotifications = notifications.filter(n => n.userId === user?.id).sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  const unreadCount = myNotifications.filter(n => !n.isRead).length;

  const handleLogout = () => {
      logout();
      navigate('/');
      setProfileOpen(false);
  };

  // Reusable Notification Dropdown
  const renderNotifications = () => (
      <div className="absolute right-0 mt-3 w-80 glass border border-white/10 rounded-2xl shadow-2xl overflow-hidden z-50 animate-slide-up origin-top-right bg-[#1a1d24]">
        <div className="p-4 border-b border-white/5 flex justify-between items-center bg-white/5">
            <h4 className="text-sm font-bold text-white">Bildirişlər</h4>
            <button onClick={clearNotifications} className="text-xs text-primary hover:text-primary-dark">Təmizlə</button>
        </div>
        <div className="max-h-64 overflow-y-auto">
            {myNotifications.length === 0 ? <div className="p-8 text-center text-gray-500 text-sm">Bildiriş yoxdur.</div> : myNotifications.map(notif => (
                <div key={notif.id} onClick={() => markNotificationRead(notif.id)} className={`p-4 border-b border-white/5 hover:bg-white/5 cursor-pointer transition-colors ${!notif.isRead ? 'bg-primary/5' : ''}`}>
                    <p className={`text-sm ${!notif.isRead ? 'font-semibold text-white' : 'text-gray-400'}`}>{notif.title}</p>
                    <p className="text-xs text-gray-500 mt-1">{notif.message}</p>
                </div>
            ))}
        </div>
    </div>
  );

  return (
    <>
    <SideDrawer isOpen={drawerOpen} onClose={() => setDrawerOpen(false)} />

    <nav 
        className={`fixed w-full z-50 transition-all duration-300 border-b 
        ${scrolled 
            ? 'bg-[#0F1115]/95 backdrop-blur-xl border-white/10 shadow-2xl py-2' 
            : 'bg-transparent border-transparent py-3 md:py-4'}`}
    >
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">

        {/* DESKTOP LAYOUT (Single Row) */}
        <div className="hidden md:flex items-center justify-between gap-8">

            {/* Left: Logo */}
            <div className="flex items-center gap-4 shrink-0">
                <Link to="/" className="flex items-center gap-2 group">
                    <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-primary to-secondary flex items-center justify-center text-white font-bold text-xl shadow-lg shadow-primary/20 group-hover:scale-105 transition-transform">D</div>
                    <span className="text-2xl font-bold text-white tracking-tight">GAME<span className="text-primary font-light">PAY</span></span>
                </Link>
            </div>

            {/* Middle: Search (Always Visible) */}
            <div className="flex-1 max-w-2xl">
                <form onSubmit={handleSearch} className="relative w-full group">
                    <input 
                        type="text" 
                        placeholder="Məhsul axtar..." 
                        className="w-full bg-white/5 border border-white/10 rounded-xl py-2.5 pl-11 pr-4 text-sm text-white focus:bg-black/40 focus:border-primary transition-all duration-300 outline-none placeholder-gray-500 shadow-inner"
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                    />
                    <Search className="absolute left-3.5 top-2.5 w-5 h-5 text-gray-500 group-focus-within:text-primary transition-colors" />
                </form>
            </div>

            {/* Right: Actions */}
            <div className="flex items-center gap-4 shrink-0">
                {isAuthenticated ? (
                    <>
                        {/* Balance with TopUp */}
                        <div className="flex items-center gap-3 bg-white/5 border border-white/10 pl-4 pr-1 py-1 rounded-xl">
                            <span className="text-sm font-mono font-bold text-white">{user?.balance.toFixed(2)} <span className="text-primary">₼</span></span>
                            <button onClick={() => navigate('/balance')} className="bg-primary hover:bg-primary-dark text-white p-1.5 rounded-lg transition-colors shadow-lg shadow-primary/20">
                                <Plus className="w-4 h-4" />
                            </button>
                        </div>

                        {/* Notifications */}
                        <div className="relative" ref={notifRef}>
                            <button onClick={() => setNotifOpen(!notifOpen)} className="relative p-2.5 bg-white/5 hover:bg-white/10 rounded-xl text-gray-400 hover:text-white transition-colors border border-white/5">
                                <Bell className="w-5 h-5" />
                                {unreadCount > 0 && <span className="absolute top-2 right-2 w-2 h-2 bg-red-500 rounded-full animate-pulse"></span>}
                            </button>
                            {notifOpen && renderNotifications()}
                        </div>

                        {/* Profile Dropdown */}
                        <div className="relative" ref={profileRef}>
                            <button onClick={() => setProfileOpen(!profileOpen)} className="flex items-center gap-2 pl-1 pr-3 py-1 rounded-xl bg-white/5 border border-white/10 hover:bg-white/10 transition-all">
                                <div className="h-9 w-9 rounded-lg bg-gradient-to-tr from-primary to-secondary flex items-center justify-center text-white font-bold shadow-lg">
                                    {user?.avatar ? <img src={user.avatar} className="w-full h-full object-cover rounded-lg"/> : user?.name.charAt(0)}
                                </div>
                                <ChevronDown className={`w-4 h-4 text-gray-400 transition-transform ${profileOpen ? 'rotate-180' : ''}`} />
                            </button>
                            {profileOpen && (
                                <div className="absolute right-0 mt-4 w-56 glass border border-white/10 rounded-2xl shadow-2xl p-2 z-50 animate-slide-up origin-top-right bg-[#1a1d24]">
                                    <Link to="/profile" onClick={() => setProfileOpen(false)} className="flex items-center gap-2 px-3 py-2 text-sm text-gray-300 hover:text-white hover:bg-white/10 rounded-lg transition-colors">
                                        <UserIcon className="w-4 h-4" /> Profil
                                    </Link>
                                    <Link to="/profile" onClick={() => setProfileOpen(false)} className="flex items-center gap-2 px-3 py-2 text-sm text-gray-300 hover:text-white hover:bg-white/10 rounded-lg transition-colors">
                                        <Heart className="w-4 h-4" /> İstək siyahısı
                                    </Link>
                                    {user?.role === 'admin' && (
                                        <Link to="/admin" onClick={() => setProfileOpen(false)} className="flex items-center gap-2 px-3 py-2 text-sm text-red-400 hover:text-red-300 hover:bg-red-500/10 rounded-lg transition-colors">
                                            Admin Panel
                                        </Link>
                                    )}
                                    <div className="h-px bg-white/5 my-2"></div>
                                    <button onClick={handleLogout} className="w-full flex items-center gap-2 px-3 py-2 text-sm text-red-400 hover:text-red-300 hover:bg-red-500/10 rounded-lg transition-colors">
                                        <LogOut className="w-4 h-4" /> Çıxış
                                    </button>
                                </div>
                            )}
                        </div>
                    </>
                ) : (
                    <div className="flex items-center gap-3">
                        <Link to="/auth" className="text-white font-bold hover:text-primary transition-colors text-sm">Daxil Ol</Link>
                        <Link to="/auth" className="bg-white text-black px-5 py-2.5 rounded-xl font-bold hover:bg-gray-200 transition-colors shadow-lg shadow-white/10 text-sm">Qeydiyyat</Link>
                    </div>
                )}
            </div>
        </div>

        {/* MOBILE LAYOUT (Compact 2 Rows) */}
        <div className="md:hidden flex flex-col gap-3">
            {/* Row 1: Menu Icon, Logo, Right Section (Notification ONLY - Removed Profile/Balance for simpler look) */}
            <div className="flex items-center justify-between">
                <div className="flex items-center gap-3">
                    <button 
                        onClick={() => setDrawerOpen(true)} 
                        className="p-2 bg-white/5 rounded-xl text-gray-300 border border-white/10 active:scale-95 transition-transform backdrop-blur-md"
                    >
                        <Menu className="w-6 h-6 text-white" />
                    </button>

                    <Link to="/" className="flex items-center gap-1">
                        <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-primary to-secondary flex items-center justify-center text-white font-bold text-lg shadow-lg">D</div>
                        <span className="font-bold text-white text-lg tracking-tight drop-shadow-md">GAME<span className="text-primary">PAY</span></span>
                    </Link>
                </div>

                <div className="flex items-center gap-2">
                    {/* Notification */}
                    <div className="relative" ref={notifRef}>
                        <button onClick={() => setNotifOpen(!notifOpen)} className="relative p-2 text-gray-400 hover:text-white bg-white/5 rounded-xl border border-white/10 backdrop-blur-md">
                            <Bell className="w-5 h-5" />
                            {unreadCount > 0 && <span className="absolute top-1 right-1 w-2.5 h-2.5 bg-red-500 rounded-full border-2 border-[#0F1115]"></span>}
                        </button>
                        {notifOpen && renderNotifications()}
                    </div>
                </div>
            </div>

            {/* Row 2: Full Width Search */}
            <form onSubmit={handleSearch} className="relative w-full">
                <input 
                    type="text" 
                    placeholder="Oyun, UC, VP axtar..." 
                    className="w-full bg-surfaceHighlight/80 backdrop-blur-md border border-white/10 rounded-xl py-2 pl-10 pr-4 text-sm text-white focus:border-primary outline-none shadow-inner"
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                />
                <Search className="absolute left-3 top-2 w-4 h-4 text-gray-500" />
            </form>
        </div>

      </div>
    </nav>
    </>
  );
};

export default Navbar;

import React from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { Home, LayoutGrid, ShoppingCart, User, MessageCircle } from 'lucide-react';
import { useApp } from '../store';

const BottomNav = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const { user, cart, openCart } = useApp();

  if (location.pathname.startsWith('/admin') || location.pathname === '/auth') {
      return null;
  }

  const isActive = (path: string) => location.pathname === path;

  const handleProfileClick = () => {
      if (user) {
          navigate('/profile');
      } else {
          navigate('/auth');
      }
  };

  return (
    <div className="md:hidden fixed bottom-0 left-0 w-full bg-[#0F1115]/95 backdrop-blur-xl border-t border-white/10 z-[60] pb-safe pt-2 h-[80px] shadow-[0_-5px_20px_rgba(0,0,0,0.5)]">
        <div className="grid grid-cols-5 h-full relative items-start pt-2">

            {/* 1. Home */}
            <button onClick={() => navigate('/')} className="flex flex-col items-center justify-center gap-1 group">
                <Home className={`w-6 h-6 transition-all duration-300 group-active:scale-90 ${isActive('/') ? 'text-primary fill-primary/20' : 'text-gray-500'}`} strokeWidth={isActive('/') ? 2.5 : 2} />
                <span className={`text-[10px] transition-colors ${isActive('/') ? 'text-white font-bold' : 'text-gray-500'}`}>Ana Səhifə</span>
            </button>

            {/* 2. Categories */}
            <button onClick={() => navigate('/categories')} className="flex flex-col items-center justify-center gap-1 group">
                <LayoutGrid className={`w-6 h-6 transition-all duration-300 group-active:scale-90 ${isActive('/categories') ? 'text-primary fill-primary/20' : 'text-gray-500'}`} strokeWidth={isActive('/categories') ? 2.5 : 2} />
                <span className={`text-[10px] transition-colors ${isActive('/categories') ? 'text-white font-bold' : 'text-gray-500'}`}>Kataloq</span>
            </button>

            {/* 3. CART (Enhanced Floating Effect) */}
            <div className="relative flex justify-center -top-8">
                <button 
                    onClick={openCart} 
                    className="absolute bg-gradient-to-tr from-primary to-secondary w-16 h-16 rounded-full border-[6px] border-[#0F1115] shadow-[0_0_20px_rgba(139,92,246,0.6)] transform transition-transform active:scale-90 hover:scale-110 flex items-center justify-center z-10 group"
                >
                    <ShoppingCart className="w-7 h-7 text-white drop-shadow-md" strokeWidth={2.5} />
                    {cart.length > 0 && (
                        <span className="absolute -top-1 -right-1 bg-red-500 text-white text-[10px] font-bold w-5 h-5 rounded-full flex items-center justify-center border-2 border-[#0F1115] animate-bounce">
                            {cart.length}
                        </span>
                    )}
                    {/* Inner Pulse Ring */}
                    <div className="absolute inset-0 rounded-full border border-white/30 animate-ping opacity-20"></div>
                </button>
                <span className="absolute -bottom-8 text-[11px] font-bold text-white drop-shadow-[0_0_5px_rgba(0,0,0,0.8)]">Səbət</span>
            </div>

            {/* 4. Support */}
            <button onClick={() => navigate('/contact')} className="flex flex-col items-center justify-center gap-1 group">
                <MessageCircle className={`w-6 h-6 transition-all duration-300 group-active:scale-90 ${isActive('/contact') ? 'text-primary fill-primary/20' : 'text-gray-500'}`} strokeWidth={isActive('/contact') ? 2.5 : 2} />
                <span className={`text-[10px] transition-colors ${isActive('/contact') ? 'text-white font-bold' : 'text-gray-500'}`}>Dəstək</span>
            </button>

            {/* 5. Profile */}
            <button onClick={handleProfileClick} className="flex flex-col items-center justify-center gap-1 group">
                <User className={`w-6 h-6 transition-all duration-300 group-active:scale-90 ${isActive('/profile') ? 'text-primary fill-primary/20' : 'text-gray-500'}`} strokeWidth={isActive('/profile') ? 2.5 : 2} />
                <span className={`text-[10px] transition-colors ${isActive('/profile') ? 'text-white font-bold' : 'text-gray-500'}`}>Profil</span>
            </button>
        </div>
    </div>
  );
};

export default BottomNav;

import React, { useState } from 'react';
import { MessageCircle, X, HelpCircle, Bot, ArrowRight, ChevronRight } from 'lucide-react';
import { useApp } from '../store';

const ChatWidget = () => {
  const { siteSettings } = useApp();
  const [isOpen, setIsOpen] = useState(false);
  const [view, setView] = useState<'home' | 'faq'>('home');

  const whatsappLink = siteSettings.socials?.whatsapp || `https://wa.me/${siteSettings.whatsappNumber.replace(/[^0-9]/g, '')}`;

  const faqList = [
      { q: "Məhsullar necə çatdırılır?", a: "Ödəniş təsdiqləndikdən dərhal sonra hesab və ya lisenziya açarı profilinizdə və ekranda görünür." },
      { q: "Zəmanət verirsiniz?", a: "Bəli, bütün məhsullarımıza rəsmi zəmanət verilir. Hər hansı problem olarsa, dərhal dəyişdirilir." },
      { q: "Ödəniş üsulları hansılardır?", a: "Bank kartı (Birbank) və ya M10/MilliÖn vasitəsilə ödəniş edə bilərsiniz." },
      { q: "Qaytarılma mümkündür?", a: "Rəqəmsal məhsullar (Key/Hesab) təbiəti etibarilə geri qaytarılmır, lakin işləmirsə dəyişdirilir." }
  ];

  // FIX: Increased bottom spacing for mobile (bottom-32) to avoid BottomNav overlap when opening the chat window
  return (
    <div className="fixed bottom-32 md:bottom-6 right-6 z-40 flex flex-col items-end font-sans">

      {isOpen && (
        <div className="mb-4 w-80 md:w-96 glass rounded-3xl shadow-2xl overflow-hidden animate-slide-up flex flex-col max-h-[500px] border border-white/10">

            {/* Header */}
            <div className="bg-gradient-to-r from-primary to-accent p-4 flex justify-between items-center text-white">
                <div>
                    <h3 className="font-bold text-md">Müştəri Dəstəyi</h3>
                    <p className="text-white/80 text-xs">Sizə necə kömək edə bilərik?</p>
                </div>
                <div className="flex gap-2">
                    {view !== 'home' && (
                        <button onClick={() => setView('home')} className="bg-white/20 p-1.5 rounded-full hover:bg-white/30 transition-colors">
                           <ArrowRight className="w-4 h-4 rotate-180" />
                        </button>
                    )}
                    <button onClick={() => setIsOpen(false)} className="bg-white/20 p-1.5 rounded-full hover:bg-white/30 transition-colors">
                        <X className="w-4 h-4" />
                    </button>
                </div>
            </div>

            <div className="bg-[#1a1d24] flex-1 overflow-y-auto">
                {view === 'home' && (
                    <div className="p-5 space-y-3">
                        <div className="text-center mb-4">
                            <div className="w-12 h-12 bg-white/10 rounded-full flex items-center justify-center mx-auto mb-2">
                                <Bot className="w-6 h-6 text-primary" />
                            </div>
                            <p className="text-gray-300 text-xs">Salam! Hər hansı sualınız varsa, aşağıdakı seçimlərdən istifadə edin.</p>
                        </div>

                        <button 
                            onClick={() => window.open(whatsappLink, '_blank')}
                            className="w-full bg-[#25D366] text-white p-3 rounded-xl flex items-center gap-3 hover:shadow-lg hover:shadow-green-500/20 transition-all group"
                        >
                            <div className="bg-white/20 p-2 rounded-full"><MessageCircle className="w-5 h-5" /></div>
                            <div className="text-left flex-1">
                                <p className="font-bold text-sm">WhatsApp</p>
                                <p className="text-[10px] opacity-90">Canlı Operatorla əlaqə</p>
                            </div>
                            <ArrowRight className="w-4 h-4 opacity-50 group-hover:translate-x-1 transition-transform" />
                        </button>

                        <button 
                            onClick={() => setView('faq')}
                            className="w-full bg-white/5 border border-white/5 text-white p-3 rounded-xl flex items-center gap-3 hover:bg-white/10 transition-all group"
                        >
                            <div className="bg-gradient-to-br from-primary to-accent p-2 rounded-full"><HelpCircle className="w-5 h-5 text-white" /></div>
                            <div className="text-left flex-1">
                                <p className="font-bold text-sm">Tez-tez Verilən Suallar</p>
                                <p className="text-[10px] text-gray-400">Ümumi məlumatlar</p>
                            </div>
                            <ChevronRight className="w-4 h-4 text-gray-500 group-hover:translate-x-1 transition-transform" />
                        </button>
                    </div>
                )}

                {view === 'faq' && (
                    <div className="p-4 space-y-3">
                        {faqList.map((item, idx) => (
                            <div key={idx} className="bg-white/5 border border-white/5 rounded-xl p-3">
                                <h4 className="font-bold text-white text-xs mb-1 flex items-start gap-2">
                                    <HelpCircle className="w-3 h-3 text-primary shrink-0 mt-0.5" />
                                    {item.q}
                                </h4>
                                <p className="text-gray-400 text-[10px] pl-5 leading-relaxed">
                                    {item.a}
                                </p>
                            </div>
                        ))}
                    </div>
                )}
            </div>
        </div>
      )}

      <button 
        onClick={() => setIsOpen(!isOpen)}
        className="bg-gradient-to-r from-primary to-accent text-white p-3.5 rounded-full shadow-[0_0_20px_rgba(99,102,241,0.4)] transition-all hover:scale-110 active:scale-95"
      >
        {isOpen ? <X className="w-6 h-6" /> : <MessageCircle className="w-6 h-6" />}
      </button>
    </div>
  );
};

export default ChatWidget;
